/**
 * @file capability.cpp
 * @author theflysong (song_of_the_fly@163.com)
 * @brief capability definition
 * @version alpha-1.0.0
 * @date 2026-02-25
 *
 * @copyright Copyright (c) 2026
 *
 */

#include <cap/capability.h>
#include <cap/permission.h>
#include <logger.h>
#include <mem/alloc.h>
#include <storage.h>
#include <sus/list.h>
#include <sustcore/capability.h>

namespace cap {
    namespace kop {
        Storage<KOP<Capability>> capability_raw;
        Storage<KOP<CGroup>> cgroup_raw;
        Storage<LockedObject<IrqSaveGuardedLock, KOP<Capability>>>
            capability_storage;
        Storage<LockedObject<IrqSaveGuardedLock, KOP<CGroup>>> cgroup_storage;

        [[nodiscard]]
        LockedObject<IrqSaveGuardedLock, KOP<Capability>> &capability() {
            return capability_storage.ref();
        }

        [[nodiscard]]
        LockedObject<IrqSaveGuardedLock, KOP<CGroup>> &cgroup() {
            return cgroup_storage.ref();
        }
    }  // namespace kop

    void init_kop() {
        kop::capability_raw.construct();
        kop::cgroup_raw.construct();
        kop::capability_storage.construct(kop::capability_raw.get());
        kop::cgroup_storage.construct(kop::cgroup_raw.get());
    }

    void *Capability::operator new(size_t size) {
        assert(size == sizeof(Capability));
        return kop::capability().get()->alloc();
    }

    void Capability::operator delete(void *ptr) {
        kop::capability().get()->free(static_cast<Capability *>(ptr));
    }

    void *CGroup::operator new(size_t size) {
        assert(size == sizeof(CGroup));
        return kop::cgroup().get()->alloc();
    }

    void CGroup::operator delete(void *ptr) {
        kop::cgroup().get()->free(static_cast<CGroup *>(ptr));
    }
}  // namespace cap

/**
 * @file cholder.h
 * @author theflysong (song_of_the_fly@163.com)
 * @brief 能力持有者
 * @version alpha-1.0.0
 * @date 2026-02-28
 *
 * @copyright Copyright (c) 2026
 *
 */

#pragma once

#include <cap/capability.h>
#include <sus/map.h>
#include <sus/raii.h>
#include <sustcore/capability.h>
#include <sustcore/errcode.h>

#include <unordered_map>
#include <utility>

namespace cap {
    // 能够持有能力的对象称为能力持有者 (Capability Holder)
    // 例如, Process就是一种典型的能力持有者.
    // 又如, VFS也是一种能力持有者, 因为它持有着文件系统的能力 (如根目录的能力).
    class CHolder {
    private:
        CSpace _space;
        size_t _id;
    public:
        CHolder(size_t _id);
        ~CHolder();

        [[nodiscard]]
        constexpr size_t id() const {
            return _id;
        }

        [[nodiscard]]
        constexpr const CSpace &space() const {
            return _space;
        }
        [[nodiscard]]
        constexpr CSpace &space() {
            return _space;
        }

        [[nodiscard]]
        Result<Capability *> access(CapIdx idx) {
            return lookup(idx);
        }

        /**
         * @brief 获取当前 CHolder 中的第一个空闲 capability 槽位.
         *
         * @return Result<CapIdx> 成功返回空闲槽位索引, 失败返回错误码.
         */
        [[nodiscard]]
        Result<CapIdx> lookup_freeslot() {
            return _space.lookup_freeslot();
        }

        /**
         * @brief 在当前 CHolder 中查找指定 capability.
         *
         * @param idx capability 槽位索引.
         * @return Result<Capability *> 成功返回 capability 指针.
         */
        [[nodiscard]]
        Result<Capability *> lookup(CapIdx idx);

        /**
         * @brief 将 payload 插入指定槽位并授予全部权限.
         *
         * @param idx 目标槽位索引.
         * @param payload 要插入的 payload.
         * @return Result<void> 成功返回空结果.
         */
        [[nodiscard]]
        Result<void> insert(CapIdx idx, Payload *payload) {
            assert(payload != nullptr);
            return insert(idx, payload, perm::allperm());
        }

        /**
         * @brief 将 payload 以指定权限插入到指定槽位.
         *
         * @param idx 目标槽位索引.
         * @param payload 要插入的 payload.
         * @param perm 新 capability 的权限位.
         * @return Result<void> 成功返回空结果.
         */
        [[nodiscard]]
        Result<void> insert(CapIdx idx, Payload *payload, b64 perm);

        /**
         * @brief 将payload插入当前CHolder中的第一个空闲槽位.
         *
         * @return 插入成功时返回新cap所在槽位.
         */
        [[nodiscard]]
        Result<CapIdx> insert_to_free(Payload *payload) {
            return insert_to_free(payload, perm::allperm());
        }

        /**
         * @brief 将payload以指定权限插入当前CHolder中的第一个空闲槽位.
         *
         * @return 插入成功时返回新cap所在槽位.
         */
        [[nodiscard]]
        Result<CapIdx> insert_to_free(Payload *payload, b64 perm);

        template <typename PayloadType, typename... Args>
        [[nodiscard]]
        Result<CapIdx> create(Args &&...args) {
            auto *payload = new PayloadType(std::forward<Args>(args)...);
            if (payload == nullptr) {
                unexpect_return(ErrCode::OUT_OF_MEMORY);
            }
            auto insert_res = insert_to_free(payload);
            if (!insert_res.has_value()) {
                delete payload;
                propagate_return(insert_res);
            }
            return insert_res.value();
        }

        [[nodiscard]]
        Result<void> remove(CapIdx idx);

        /**
         * @brief 清空当前 CHolder 中的所有 capability.
         */
        void clear();

        [[nodiscard]]
        Result<CapIdx> clone(CapIdx src_idx);

        [[nodiscard]]
        Result<CapIdx> derive(CapIdx src_idx, b64 new_perm);

        [[nodiscard]]
        Result<void> downgrade(CapIdx idx, b64 new_perm);

        /**
         * @brief 将当前holder中的cap传递到目标holder空闲槽位.
         *
         * CLONE 权限会复制cap; MIGRATE/MIGRATE_ONCE 权限会在目标插入成功后
         * 消费源slot. 目标cap不会携带 MIGRATE_ONCE 位.
         */
        [[nodiscard]]
        Result<CapIdx> transfer_to(CHolder &dst, CapIdx src_idx);

        [[nodiscard]]
        Result<void> copy_all_to(CHolder &dst) const;

    private:
        [[nodiscard]]
        Result<void> set_slot(CapIdx idx, Capability *cap);

        [[nodiscard]]
        Result<Capability *> take_slot(CapIdx idx);
    };

    class CHolderManager {
    private:
        size_t __cur_id = 0;
        constexpr size_t _new_id() {
            return __cur_id++;
        }
        std::unordered_map<size_t, CHolder *> _holders;
        size_t _timestamp = 1;  // 用于记录发送记录的时间戳, 每次发送能力时递增
    public:
        static void init();
        static bool initialized();
        static CHolderManager &inst();

        CHolderManager() = default;

        [[nodiscard]]
        Result<CHolder *> get_holder(size_t _id) const {
            return _holders.at_nt(_id)
                .transform_error(always(ErrCode::OUT_OF_BOUNDARY))
                .transform([](const auto *holder) {
                    return holder == nullptr ? nullptr : *holder;
                });
        }

        template <typename... Args>
        Result<CHolder *> create_holder(Args &&...args) {
            size_t _id  = _new_id();
            auto holder = new CHolder(_id, std::forward<Args>(args)...);
            _holders[_id] = holder;
            return holder;
        }

        Result<void> remove_holder(size_t _id) {
            return get_holder(_id).and_then([&](CHolder *holder) {
                delete holder;
                _holders.erase(_id);
                void_return();
            });
        }

        [[nodiscard]]
        size_t timestamp() {
            return _timestamp++;
        }
    };
}  // namespace cap

/**
 * @file cholder.cpp
 * @author theflysong (song_of_the_fly@163.com)
 * @brief 能力持有者
 * @version alpha-1.0.0
 * @date 2026-02-28
 *
 * @copyright Copyright (c) 2026
 *
 */

#include <cap/cholder.h>
#include <env.h>
#include <guard.h>
#include <logger.h>
#include <object/memory.h>
#include <object/perm.h>
#include <sustcore/capability.h>
#include <task/scheduler.h>
#include <task/task_struct.h>

#include <cassert>

namespace {
    // NOLINTNEXTLINE(cppcoreguidelines-avoid-non-const-global-variables)
    static cap::CHolderManager inst_cholder_manager;
    static bool inst_cholder_manager_initialized = false;
}  // namespace

namespace cap {
    void CHolderManager::init() {
        // call the constructor explicitly to ensure the instance is initialized
        // before use
        new (&inst_cholder_manager) CHolderManager();
        inst_cholder_manager_initialized = true;
    }

    bool CHolderManager::initialized() {
        return inst_cholder_manager_initialized;
    }

    CHolderManager &CHolderManager::inst() {
        if (!initialized()) {
            panic("CHolderManager 未初始化!");
        }
        return inst_cholder_manager;
    }

    CHolder::CHolder(size_t id) : _space(), _id(id) {}

    CHolder::~CHolder() {}

    Result<Capability *> CHolder::lookup(CapIdx idx) {
        if (!cap::valid(idx)) {
            unexpect_return(ErrCode::TYPE_NOT_MATCHED);
        }

        Capability *cap = _space.get(idx);
        if (cap == nullptr) {
            unexpect_return(ErrCode::OUT_OF_BOUNDARY);
        }

        return cap;
    }

    Result<void> CHolder::set_slot(CapIdx idx, Capability *cap) {
        if (!cap::valid(idx)) {
            unexpect_return(ErrCode::TYPE_NOT_MATCHED);
        }

        return _space.set(idx, cap);
    }

    Result<Capability *> CHolder::take_slot(CapIdx idx) {
        if (!cap::valid(idx)) {
            unexpect_return(ErrCode::TYPE_NOT_MATCHED);
        }

        Capability *cap = _space.take(idx);
        if (cap == nullptr) {
            unexpect_return(ErrCode::OUT_OF_BOUNDARY);
        }

        return cap;
    }

    Result<void> CHolder::insert(CapIdx idx, Payload *payload,
                                 b64 permissions) {
        if (!cap::valid(idx)) {
            unexpect_return(ErrCode::TYPE_NOT_MATCHED);
        }
        if (payload == nullptr) {
            unexpect_return(ErrCode::NULLPTR);
        }
        if (_space.get(idx) != nullptr) {
            unexpect_return(ErrCode::SLOT_BUSY);
        }

        auto *cap = new Capability(payload, permissions);
        if (cap == nullptr) {
            unexpect_return(ErrCode::OUT_OF_MEMORY);
        }

        auto set_res = set_slot(idx, cap);
        assert(set_res.has_value());
        return set_res;
    }

    Result<CapIdx> CHolder::insert_to_free(Payload *payload, b64 permissions) {
        auto slot_res = lookup_freeslot();
        propagate(slot_res);
        auto insert_res = insert(slot_res.value(), payload, permissions);
        propagate(insert_res);
        return slot_res.value();
    }

    Result<void> CHolder::remove(CapIdx idx) {
        auto cap_res = lookup(idx);
        propagate(cap_res);

        if (cap_res.value() == nullptr) {
            loggers::CAPABILITY::WARN("尝试移除空槽位 {}", idx);
            void_return();
        }

        return set_slot(idx, nullptr);
    }

    void CHolder::clear() {
        _space.clear();
    }

    Result<CapIdx> CHolder::clone(CapIdx src_idx) {
        auto cap_res = lookup(src_idx);
        propagate(cap_res);

        Capability *src_cap = cap_res.value();
        if (!perm::imply(src_cap->perm(), perm::basic::CLONE)) {
            unexpect_return(ErrCode::INSUFFICIENT_PERMISSIONS);
        }

        auto target_res = lookup_freeslot();
        propagate(target_res);
        CapIdx target_idx = target_res.value();

        auto *cloned_cap = src_cap->clone();
        auto set_res     = set_slot(target_idx, cloned_cap);
        if (!set_res.has_value()) {
            delete cloned_cap;
            propagate_return(set_res);
        }
        auto *memory = src_cap->payload_as<MemoryPayload>();
        if (memory != nullptr && !memory->shared &&
            env::inst().tmm() != nullptr)
        {
            auto cow_res = env::inst().tmm()->protect_memory_cow(memory);
            if (!cow_res.has_value()) {
                auto remove_res = set_slot(target_idx, nullptr);
                assert(remove_res.has_value());
                propagate_return(cow_res);
            }
        }
        return target_idx;
    }

    Result<CapIdx> CHolder::derive(CapIdx src_idx, b64 new_perm) {
        auto clone_res = clone(src_idx);
        propagate(clone_res);
        CapIdx target_idx = clone_res.value();

        auto clone_guard = remove_guard(this, target_idx);

        auto cap_res = lookup(target_idx);
        assert(cap_res.has_value());
        auto downgrade_res = cap_res.value()->downgrade(new_perm);
        propagate(downgrade_res);

        clone_guard.release();
        return target_idx;
    }

    Result<void> CHolder::downgrade(CapIdx idx, b64 new_perm) {
        auto cap_res = lookup(idx);
        propagate(cap_res);

        return cap_res.value()->downgrade(new_perm);
    }

    Result<CapIdx> CHolder::transfer_to(CHolder &dst, CapIdx src_idx) {
        auto cap_res = lookup(src_idx);
        propagate(cap_res);
        Capability *src_cap = cap_res.value();

        if (src_cap->imply(perm::basic::CLONE)) {
            auto *cloned_cap = src_cap->clone();
            if (cloned_cap == nullptr) {
                unexpect_return(ErrCode::OUT_OF_MEMORY);
            }

            auto target_res = dst.lookup_freeslot();
            if (!target_res.has_value()) {
                delete cloned_cap;
                propagate_return(target_res);
            }

            auto set_res = dst.set_slot(target_res.value(), cloned_cap);
            if (!set_res.has_value()) {
                delete cloned_cap;
                propagate_return(set_res);
            }
            return target_res.value();
        }

        if (!src_cap->imply(perm::basic::MIGRATE) &&
            !src_cap->imply(perm::basic::MIGRATE_ONCE))
        {
            unexpect_return(ErrCode::INSUFFICIENT_PERMISSIONS);
        }

        b64 delivered_perm = src_cap->perm() & ~perm::basic::MIGRATE_ONCE;
        auto insert_res = dst.insert_to_free(src_cap->payload(), delivered_perm);
        propagate(insert_res);

        auto remove_res = remove(src_idx);
        if (!remove_res.has_value()) {
            auto rollback_res = dst.remove(insert_res.value());
            assert(rollback_res.has_value());
            propagate_return(remove_res);
        }
        return insert_res.value();
    }

    Result<void> CHolder::copy_all_to(CHolder &dst) const {
        ErrCode err = ErrCode::SUCCESS;
        _space.foreach ([&](CapIdx idx, Capability *cap) {
            if (err != ErrCode::SUCCESS) {
                return;
            }
            auto insert_res = dst.insert(idx, cap->payload(), cap->perm());
            if (!insert_res.has_value()) {
                err = insert_res.error();
            }
        });
        if (err != ErrCode::SUCCESS) {
            unexpect_return(err);
        }
        void_return();
    }
}  // namespace cap

/**
 * @file permission.h
 * @author theflysong (song_of_the_fly@163.com)
 * @brief 权限
 * @version alpha-1.0.0
 * @date 2026-02-06
 *
 * @copyright Copyright (c) 2026
 *
 */

#pragma once

#include <object/perm.h>
#include <sus/types.h>

namespace perm {
    // 权限位, 低16位保留给基础能力使用, 剩余48位供派生能力使用
    constexpr bool imply(b64 owned, b64 required) noexcept {
        return BITS_IMPLIES(owned, required);
    }

    constexpr b64 allperm() noexcept {
        return ~0ULL;
