    void switch_pgd(TaskMemoryManager *tmm) {
        // 只在页表不为null且不等于当前页表时才切换
        if (tmm->pgd().nonnull() && tmm->pgd() != env::inst().pgd()) {
            tmm->pman().switch_root();
        }
        // 更新 environment 中的 task memory
        env::inst().tmm(env::key::set()) = tmm;
