        [[nodiscard]]
        Result<void> replace_page(size_t offset, PhyAddr new_addr) noexcept;
        /**
         * @brief 从 payload 中读取指定偏移范围的数据. 
         *
         * 未分配页会先懒分配为零页, 然后再执行读取. 
         *
         * @param offset 起始偏移. 
         * @param data 输出缓冲区. 
