    TCB      = 0x008,
    ENDPOINT = 0x009,
    MEMORY   = 0x00A,
    REPLY    = 0x00B,
    VMOUNT   = 0x00C,
    PIPE_READ_END  = 0x00D,
    PIPE_WRITE_END = 0x00E,
};

constexpr bool operator&(PayloadType a, PayloadType b) {
    return (static_cast<b64>(a) & static_cast<b64>(b)) != 0;
}

constexpr const char *to_string(PayloadType type) {
    switch (type) {
        case PayloadType::NONE:     return "NONE";
        case PayloadType::INTOBJ:   return "INTOBJ";
        case PayloadType::SINTOBJ:  return "SINTOBJ";
        case PayloadType::VFILE:    return "VFILE";
        case PayloadType::VDIR:     return "VDIR";
        case PayloadType::NOTIF:    return "NOTIF";
        case PayloadType::MUTEX:    return "MUTEX";
        case PayloadType::PCB:      return "PCB";
        case PayloadType::TCB:      return "TCB";
        case PayloadType::ENDPOINT: return "ENDPOINT";
        case PayloadType::MEMORY:   return "MEMORY";
        case PayloadType::REPLY:    return "REPLY";
        case PayloadType::VMOUNT:   return "VMOUNT";
        case PayloadType::PIPE_READ_END:  return "PIPE_READ_END";
        case PayloadType::PIPE_WRITE_END: return "PIPE_WRITE_END";
        default:                    return "UNKNOWN";
    }
}

using CapIdx  = b64;
using RecvIdx = b64;

struct CapInfo {
    PayloadType type;
    b64 permissions;
};

namespace cap {
    template <b64 mask>
    consteval b64 CALC_MASK_SHIFT() {
        static_assert(mask != 0, "Mask cannot be zero");
        b64 shift = 0;
        b64 m     = mask;
        while ((m & 1) == 0) {
            m >>= 1;
            ++shift;
        }
        return shift;
    }

    constexpr CapIdx null  = 0;
    constexpr CapIdx error = 0xFFFFFFFFFFFFFFFF;

    // 最高几位留空以允许系统调用返回负值
    constexpr b64 MASK_VALID  = 0x1000000000000000;
    constexpr b64 MASK_SLOT   = 0x00000000000000FF;
    constexpr b64 SLOT_SHIFT  = CALC_MASK_SHIFT<MASK_SLOT>();
    constexpr b64 MASK_GROUP  = 0x00000000000FFF00;
    constexpr b64 GROUP_SHIFT = CALC_MASK_SHIFT<MASK_GROUP>();
    constexpr b64 MASK_RSVD =
        0xFFFFFFFFFFFFFFFF & ~(MASK_VALID | MASK_SLOT | MASK_GROUP);

    // 计算掩码的位宽 (从最低有效位到最高有效位的位数）
    template <b64 mask>
    consteval b64 CALC_MASK_WIDTH() {
        static_assert(mask != 0, "Mask cannot be zero");
        // 先移除最低位之前的零位
        b64 low   = CALC_MASK_SHIFT<mask>();
        b64 m     = mask >> low;
        // 计算剩余部分的位数
        b64 width = 0;
        while (m != 0) {
            m >>= 1;
            ++width;
        }
        return width;
    }

    // CSpace中的CGroup数量 (由 MASK_GROUP 的位宽决定)
    constexpr size_t CSPACE_SIZE  = 1ULL << CALC_MASK_WIDTH<MASK_GROUP>();
    // CGroup中的槽位数 (由 MASK_SLOT 的位宽决定)
    // 每个槽位都存放着一个 Capability
    constexpr size_t CGROUP_SLOTS = 1ULL << CALC_MASK_WIDTH<MASK_SLOT>();

    // 每个CSpace中都有若干个CGroup, 每个CGroup又有若干个Capability
    // 因此CSpace的容量为:
    constexpr size_t CSPACE_CAPACITY = CSPACE_SIZE * CGROUP_SLOTS;

    constexpr bool valid(CapIdx idx) {
        return (idx & MASK_VALID) != 0 && (idx & MASK_RSVD) == 0;
    }

    constexpr CapIdx make(b64 group, b64 slot) {
        return MASK_VALID | ((group << GROUP_SHIFT) & MASK_GROUP) |
               (slot & MASK_SLOT);
    }

    constexpr b64 group(CapIdx idx) {
        return (idx & MASK_GROUP) >> GROUP_SHIFT;
    }

    constexpr b64 slot(CapIdx idx) {
        return (idx & MASK_SLOT) >> SLOT_SHIFT;
    }
}  // namespace cap

static_assert(sizeof(CapIdx) == sizeof(b64), "CapIdx must be 64 bits in size");

/**
 * @file schdbase.h
 * @author theflysong (song_of_the_fly@163.com)
 * @brief scheduler base
 * @version alpha-1.0.0
 * @date 2026-03-30
 *
 * @copyright Copyright (c) 2026
 *
 */

#pragma once

#include <sus/list.h>
#include <sus/nonnull.h>
#include <sus/types.h>
#include <sustcore/errcode.h>

#include <atomic>
#include <concepts>

enum class ThreadState {
    EMPTY                   = 0,
    INITIALIZATION          = 1,
    READY                   = 2,
    RUNNING                 = 3,
    YIELD                   = 4,
    INTERRUPTIBLE_WAITING   = 5,
    UNINTERRUPTIBLE_WAITING = 6,
    DYING                   = 7
};

constexpr const char *to_string(ThreadState state) {
    switch (state) {
        case ThreadState::EMPTY:                   return "EMPTY";
        case ThreadState::INITIALIZATION:          return "INITIALIZATION";
        case ThreadState::READY:                   return "READY";
        case ThreadState::RUNNING:                 return "RUNNING";
        case ThreadState::YIELD:                   return "YIELD";
        case ThreadState::INTERRUPTIBLE_WAITING:   return "INTERRUPTIBLE_WAITING";
        case ThreadState::UNINTERRUPTIBLE_WAITING: return "UNINTERRUPTIBLE_WAITING";
        case ThreadState::DYING:                   return "DYING";
        default:                                   return "UNKNOWN";
    }
}

namespace schd {
    // BOT is the lowest priority, served as the minimum of the class type
    // however, there is no actual BOT class, it's just a placeholder for the
    // end of the class type range
    enum class ClassType {
        BOT  = 0,
        IDLE = 1,
        FCFS = 2,
        RR   = 3,
        INIT = 4,
        RT   = 5
    };

    constexpr const char *to_cstring(ClassType type) {
        switch (type) {
            case ClassType::RT:   return "RT";
            case ClassType::INIT: return "INIT";
            case ClassType::RR:   return "RR";
            case ClassType::FCFS: return "FCFS";
            case ClassType::IDLE: return "IDLE";
            case ClassType::BOT:  return "BOT";
        }
        return "UNKNOWN";
    }

    struct SchedMeta {
        ThreadState state;
        util::ListHead<SchedMeta> rq_head;
        std::atomic<b64> flags = 0;

        constexpr static b64 FLAGS_NEED_RESCHED = 0x1;
        constexpr static b64 FLAGS_PREEMPT_DISABLED = 0x2;

        template <b64 set_flags>
        constexpr void flags_set() {
            flags |= set_flags;
        }

        template <b64 reset_flags>
        constexpr void flags_reset() {
            flags &= ~reset_flags;
        }

        template <b64 check_flags>
        [[nodiscard]]
        constexpr bool flags_check() const {
            return (flags & check_flags) == check_flags;
        }

        template <typename SUType>
        constexpr static size_t ENTITY_OFFSET = offsetof(SUType, basic_entity);

        template <typename SUType>
        inline static util::nonnull<SchedMeta *> as_entity(
            util::nonnull<SUType *> unit) {
            return util::nnullforce(&unit->basic_entity);
        }

        template <typename SUType>
        inline static util::nonnull<SUType *> asunit(
            util::nonnull<SchedMeta *> entity) {
            auto *entity_ptr = reinterpret_cast<char *>(entity.get());
            auto *su_ptr     = entity_ptr - ENTITY_OFFSET<SUType>;
            return util::nnullforce(reinterpret_cast<SUType *>(su_ptr));
        }
    };

    struct RQ {
        util::IntrusiveList<SchedMeta, &SchedMeta::rq_head> rt_list;
        util::IntrusiveList<SchedMeta, &SchedMeta::rq_head> fcfs_list;
        util::IntrusiveList<SchedMeta, &SchedMeta::rq_head> rr_list;
    };

    template <typename SU>
    class BaseSched {
    public:
        using SUType         = SU;
        virtual ~BaseSched() = default;

        SchedMeta *cursched = nullptr;

        inline util::nonnull<SchedMeta *> asmeta(util::nonnull<SUType *> unit) {
            return SchedMeta::as_entity(unit);
        }

        inline util::nonnull<SUType *> asunit(util::nonnull<SchedMeta *> meta) {
            return SchedMeta::asunit<SUType>(meta);
        }

        virtual Result<util::nonnull<SUType *>> current() {
            if (cursched == nullptr) {
                unexpect_return(ErrCode::NO_RUNNABLE_THREAD);
            }
            return asunit(util::nnullforce(cursched));
        }

        /**
         * @brief 将调度单元加入就绪队列
         *
         * @param rq 调度器的就绪队列
         * @param unit 需要入队的调度单元
         */
        virtual Result<void> enqueue(util::nonnull<RQ *> rq,
                                     util::nonnull<SUType *> unit) = 0;
        /**
         * @brief 将调度单元从就绪队列中移除
         *
         * @param rq 调度器的就绪队列
         * @param unit 需要移除的调度单元
         */
        virtual Result<void> dequeue(util::nonnull<RQ *> rq,
                                     util::nonnull<SUType *> unit) = 0;
        /**
         * @brief 选择下一个要运行的调度单元
         *
         * 执行该函数时, 调度器会把 cursched 指针指向下一个要运行的调度单元
         * 将下一个要运行的调度单元的状态设置为 RUNNING, 并从就绪队列中移除它
         *
         * @param rq 调度器的就绪队列
         * @return Result<util::nonnull<SUType *>> 下一个要运行的调度单元
         */
        virtual Result<util::nonnull<SUType *>> pick_next(
            util::nonnull<RQ *> rq)                                 = 0;
        /**
         * @brief 将调度单元放回就绪队列
         *
         * @param rq 调度器的就绪队列
         * @param unit 需要放回的调度单元
         */
        virtual Result<void> put_prev(util::nonnull<RQ *> rq,
                                      util::nonnull<SUType *> unit) = 0;
        /**
         * @brief 主动让出 CPU
         *
         * 这么做并不会立即切换到下一个任务, 而是为当前任务添加一个 NEED_RESCHED
         * 标志, 让调度器在合适的时候切换到下一个任务
         *
         * @param rq 调度器的就绪队列
         */
        virtual Result<void> yield(util::nonnull<RQ *> rq)          = 0;
        /**
         * @brief 每个tick调用一次, 用于更新调度单元的状态
         *
         * @param rq 调度器的就绪队列
         * @param unit 当前正在运行的调度单元
         */
        virtual Result<void> on_tick(util::nonnull<RQ *> rq,
                                     util::nonnull<SUType *> unit)  = 0;

        /**
         * @brief 判断当前任务是否要被new_su抢占(其中new_su的class
         * type总是大于当前任务的class type)
         *
         * @param rq 调度器的就绪队列
         * @param new_su 即将要运行的调度单元
         * @return true 需要抢占当前任务
         * @return false 不需要抢占当前任务
         */
        virtual bool check_preempt_curr(util::nonnull<RQ *> rq,
                                        util::nonnull<SUType *> new_su) = 0;
    };

    template <template <typename> class SchdPolicy, typename SU>
    concept SchdClassBasicTrait =
        std::derived_from<SchdPolicy<SU>, BaseSched<SU>> &&
        requires(SchdPolicy<SU> &policy, util::nonnull<RQ *> rq,
                 util::nonnull<SU *> unit) {
            {
                SchdPolicy<SU>::CLASS_TYPE
            } -> std::convertible_to<ClassType>;
        };

    template <template <typename> class SchdPolicy, typename SU>
    concept SchdClassTrait = SchdClassBasicTrait<SchdPolicy, SU>;
}  // namespace schd

