    static constexpr size_t BLOCK_SIZE = 512;

    template <typename T>
    inline size_t parse_octal(const T &field) {
        // 使用模板来适配不同长度的字符八进制字段
        size_t result = 0;
        for (size_t i = 0; i < sizeof(field); ++i) {
            char c = field[i];
            if (c == '\0') {
                break;
            }
            if (c < '0' || c > '7') {
                // 非法字符, 返回当前结果
                break;
            }
            result = (result << 3) + (c - '0');
        }
        return result;
    }

    // NOLINTBEGIN
    union TarBlock {
        struct ustar_header {
            char name[100];
            char mode[8];
            char uid[8];
            char gid[8];
            char size[12];
            char mtime[12];
            char checksum[8];
            char typeflag[1];
            char linkname[100];
            char magic[6];
            char version[2];
            char uname[32];
            char gname[32];
            char devmajor[8];
            char devminor[8];
            char prefix[155];
            char pad[12];
        } header;
        uint8_t raw[BLOCK_SIZE];

        inline bool is_header() const {
            return header.magic[0] == 'u' && header.magic[1] == 's' &&
                   header.magic[2] == 't' && header.magic[3] == 'a' &&
                   header.magic[4] == 'r';
        }

        inline bool is_empty() const {
            for (size_t i = 0; i < BLOCK_SIZE; ++i) {
                if (raw[i] != 0)
                    return false;
            }
            return true;
        }

        inline unsigned int calc_checksum() const {
            TarBlock temp           = *this;
            temp.header.checksum[0] = ' ';
            temp.header.checksum[1] = ' ';
            temp.header.checksum[2] = ' ';
            temp.header.checksum[3] = ' ';
            temp.header.checksum[4] = ' ';
            temp.header.checksum[5] = ' ';
            temp.header.checksum[6] = ' ';
            temp.header.checksum[7] = ' ';

            unsigned int sum = 0;
            for (size_t i = 0; i < BLOCK_SIZE; ++i) {
                sum += static_cast<unsigned int>(temp.raw[i]);
            }
            return sum;
        }
    };
